using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr documents = app->documents();
    if (!documents)
        return false;

    Ptr doc = documents->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    // Get the root component of the active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create sketch in root component
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;
    Ptr xz = rootComp->xZConstructionPlane();
    if (!xz)
        return false;
    Ptr sketch = sketches->add(xz);
    if (!sketch)
        return false;
    Ptr sketchPts = sketch->sketchPoints();
    if (!sketchPts)
        return false;
    Ptr point = Point3D::create(1, 0, 1);
    if (!point)
        return false;
    Ptr sketchPt = sketchPts->add(point);
    if (!sketchPt)
        return false;
    Ptr sketchCurves = sketch->sketchCurves();
    if (!sketchCurves)
        return false;
    Ptr sketchCircles = sketchCurves->sketchCircles();
    if (!sketchCircles)
        return false;
    Ptr centerPoint = Point3D::create(0, 0, 0);
    if (!centerPoint)
        return false;
    Ptr circle = sketchCircles->addByCenterRadius(centerPoint, 2.5);
    if (!circle)
        return false;

    // Get the profile defined by the circle
    Ptr profs = sketch->profiles();
    if (!profs)
        return false;
    Ptr profile = profs->item(0);
    if (!profile)
        return false;

    // Create an extrude input and make sure it's in a new component
    Ptr feats = rootComp->features();
    if (!feats)
        return false;
    Ptr extrudes = feats->extrudeFeatures();
    if (!extrudes)
        return false;
    Ptr extInput = extrudes->createInput(profile, FeatureOperations::NewComponentFeatureOperation);
    if (!extInput)
        return false;

    // Set the extrude input
    Ptr distance = ValueInput::createByString("50 mm");
    if (!distance)
        return false;
    extInput->setDistanceExtent(false, distance);
    extInput->isSolid(true);

    // Create the extrude
    Ptr ext = extrudes->add(extInput);
    if (!ext)
        return false;

    // Get the end face of the created extrude
    Ptr endFaces = ext->endFaces();
    if (!endFaces)
        return false;
    Ptr endFace = endFaces->item(0);
    if (!endFace)
        return false;

    // Create the joint geometry
    Ptr jointGeometry = JointGeometry::createByPlanarFace(endFace, nullptr, CenterKeyPoint);
    if (!jointGeometry)
        return false;

    // Create JointOrigininput
    Ptr jointOrigs = rootComp->jointOrigins();
    if (!jointOrigs)
        return false;
    Ptr jointOriginInput = jointOrigs->createInput(jointGeometry);
    if (!jointOriginInput)
        return false;

    // Create the JointOrigin
    Ptr jointOrigin = jointOrigs->add(jointOriginInput);
    if (!jointOrigin)
        return false;

    // Fit to window
    Ptr viewPort = app->activeViewport();
    if (!viewPort)
        return false;
    Ptr cam = viewPort->camera();
    if (!cam)
        return false;
    cam->isFitView(true);
    viewPort->camera(cam);


    return true;
}
